### Swift Protocol Delegation

Delegation is a design pattern where one object sends messages to another object (the delegate) to handle specific events. Protocols define the delegate interface, enabling loose coupling.

**Delegation Pattern:**

```swift
// 1. Define the protocol
protocol TaskDelegate: AnyObject {
    func taskDidStart(_ task: String)
    func taskDidComplete(_ task: String, result: String)
    func taskDidFail(_ task: String, error: String)
}

// 2. The delegating class
class TaskManager {
    weak var delegate: TaskDelegate?

    func execute(task: String) {
        delegate?.taskDidStart(task)

        // Simulate work
        let success = Bool.random()
        if success {
            delegate?.taskDidComplete(task, result: "Success")
        } else {
            delegate?.taskDidFail(task, error: "Unknown error")
        }
    }
}

// 3. The delegate
class ViewModel: TaskDelegate {
    func taskDidStart(_ task: String) {
        print("Starting: \(task)")
    }

    func taskDidComplete(_ task: String, result: String) {
        print("Completed: \(task) - \(result)")
    }

    func taskDidFail(_ task: String, error: String) {
        print("Failed: \(task) - \(error)")
    }
}

let manager = TaskManager()
let viewModel = ViewModel()
manager.delegate = viewModel
manager.execute(task: "Data Load")
```

**Key Aspects:**

| Aspect | Convention |
|--------|------------|
| Delegate property | `weak var delegate: DelegateProtocol?` |
| Avoid retain cycles | Use `weak` with `AnyObject` protocol |
| Optional methods | Use protocol extensions for defaults |
| Naming | `SendingClassDelegate` pattern |

**Optional Protocol Methods:**

```swift
@objc protocol DataSource {
    // Required
    func numberOfItems() -> Int
    // Optional
    @objc optional func titleForItem(at index: Int) -> String
}

class MyDataSource: DataSource {
    func numberOfItems() -> Int { 10 }
    // titleForItem is optional
}
```

> **Key Point:** Delegation is widely used in iOS SDK (UITableViewDelegate, UITextFieldDelegate). The delegate property should be `weak` to prevent strong reference cycles.

With Swift protocol extensions, you can make methods optional without `@objc` by providing default implementations:

```swift
protocol OptionalDelegate: AnyObject {
    func requiredMethod()
    func optionalMethod()
}

extension OptionalDelegate {
    func optionalMethod() { }  // Default empty implementation
}
```

codeExample:
import Foundation

// Delegate protocol
protocol DownloadManagerDelegate: AnyObject {
    func downloadDidStart(url: String)
    func downloadProgress(url: String, percent: Double)
    func downloadDidFinish(url: String, data: Data)
    func downloadDidFail(url: String, error: String)
}

// Delegating class
class DownloadManager {
    weak var delegate: DownloadManagerDelegate?

    func download(from url: String) {
        delegate?.downloadDidStart(url: url)

        for progress in stride(from: 0.0, through: 1.0, by: 0.25) {
            delegate?.downloadProgress(url: url, percent: progress)
        }

        let success = true
        if success {
            let data = Data("Sample content".utf8)
            delegate?.downloadDidFinish(url: url, data: data)
        } else {
            delegate?.downloadDidFail(url: url, error: "Connection lost")
        }
    }
}

// Delegate implementation
class FileDownloader: DownloadManagerDelegate {
    let name: String

    init(name: String) { self.name = name }

    func downloadDidStart(url: String) {
        print("\(name): Starting download from \(url)")
    }

    func downloadProgress(url: String, percent: Double) {
        print("\(name): \(Int(percent * 100))%")
    }

    func downloadDidFinish(url: String, data: Data) {
        print("\(name): Downloaded \(data.count) bytes")
    }

    func downloadDidFail(url: String, error: String) {
        print("\(name): Failed - \(error)")
    }
}

let manager = DownloadManager()
let downloader = FileDownloader(name: "Downloader1")
manager.delegate = downloader
manager.download(from: "https://example.com/file.zip")
